use distributed_inference::gnosis_foil::{
    expected_fibonacci, fibonacci_fast_kernel_measurement, foil_core_boost_retention_floor,
    rf_fibonacci_compare_baseline, rf_fibonacci_compare_fast_kernel, rf_fibonacci_measurement,
    FibonacciFastKernelMeasurement, GnosisFoilBackend, GnosisFoilBorrowedRawIngressEngine,
    GnosisFoilDirectDeviceReadEngine, GnosisFoilEngineKind, GnosisFoilRawIngressDescriptor,
    GnosisFoilRawSampleFormat, GnosisFoilRtl2832BulkEngine, RfAdditionTrace,
    RfFibonacciBaselineComparison, RfFibonacciFastKernelComparison, Rtl2832BulkConfig,
    FOIL_SMART_SKIP_ZERO_DRAG_THEOREM_ID,
};
use distributed_inference::pleromatic_frame::PleromaticFrame;
use distributed_inference::rf_physics_cpu::{
    RfPhysicsCpuObservation, RfSignalGate, MONSTER_VECTOR_FLOOR,
};
use serde::Serialize;
use std::env;
use std::fs::{self, File};
use std::time::Instant;

const FIB_TARGET: u32 = 20;
const FIB20_BINARY_REPORT_SIZE: usize = 96;
const FIB20_BINARY_REPORT_MAGIC: [u8; 4] = *b"BWF2";
const RF_SMART_SKIP_RETENTION_FLOOR: u64 = foil_core_boost_retention_floor();

#[derive(Serialize)]
struct Fib20HardwareReport {
    workload: String,
    primitive: &'static str,
    n: u32,
    value: u64,
    expected: Option<u64>,
    verified: bool,
    repetitions: u32,
    rf_addition_count: usize,
    elapsed_ns: u128,
    elapsed_ms: f64,
    timing: Option<Fib20HardwareTiming>,
    smart_skip_cache_hit_count: usize,
    smart_skip_retained_witness_hits: usize,
    smart_skip_recomputable_skips: usize,
    smart_skip_baseline_work: usize,
    smart_skip_executed_work: usize,
    smart_skip_saved_work: usize,
    smart_skip_saved_work_ratio: f64,
    smart_skip_zero_drag_theorem_id: Option<&'static str>,
    input_frame: Option<String>,
    source_id: Option<String>,
    byte_count: Option<usize>,
    max_energy: Option<u8>,
    mean_energy: Option<f32>,
    rf_computable: bool,
    rf_addition_sample: Vec<RfAdditionTrace>,
    observation: RfPhysicsCpuObservation,
    baseline_comparison: Option<RfFibonacciBaselineComparison>,
    fast_kernel: Option<FibonacciFastKernelMeasurement>,
    fast_kernel_comparison: Option<RfFibonacciFastKernelComparison>,
}

#[derive(Serialize)]
struct Fib20HardwareTiming {
    read_observation_ns: u128,
    compute_ns: u128,
    serialize_ns: u128,
    report_write_ns: u128,
    stdout_ns: u128,
    total_ns: u128,
}

struct Fib20BinaryReport {
    n: u32,
    repetitions: u32,
    value: u64,
    expected: u64,
    elapsed_ns: u64,
    rf_addition_count: u64,
    smart_skip_cache_hit_count: u64,
    smart_skip_retained_witness_hits: u64,
    smart_skip_recomputable_skips: u64,
    rf_selected_channels: u16,
    rf_candidate_count: u16,
    rf_bisided_score: u16,
    verified: bool,
}

impl Fib20BinaryReport {
    fn to_bytes(&self) -> [u8; FIB20_BINARY_REPORT_SIZE] {
        let mut bytes = [0_u8; FIB20_BINARY_REPORT_SIZE];
        bytes[0..4].copy_from_slice(&FIB20_BINARY_REPORT_MAGIC);
        bytes[4] = 1;
        bytes[5] = u8::from(self.verified);
        bytes[8..12].copy_from_slice(&self.n.to_le_bytes());
        bytes[12..16].copy_from_slice(&self.repetitions.to_le_bytes());
        bytes[16..24].copy_from_slice(&self.value.to_le_bytes());
        bytes[24..32].copy_from_slice(&self.expected.to_le_bytes());
        bytes[32..40].copy_from_slice(&self.elapsed_ns.to_le_bytes());
        bytes[40..48].copy_from_slice(&self.rf_addition_count.to_le_bytes());
        bytes[48..56].copy_from_slice(&self.smart_skip_cache_hit_count.to_le_bytes());
        bytes[56..64].copy_from_slice(&self.smart_skip_retained_witness_hits.to_le_bytes());
        bytes[64..72].copy_from_slice(&self.smart_skip_recomputable_skips.to_le_bytes());
        bytes[72..74].copy_from_slice(&self.rf_selected_channels.to_le_bytes());
        bytes[74..76].copy_from_slice(&self.rf_candidate_count.to_le_bytes());
        bytes[76..78].copy_from_slice(&self.rf_bisided_score.to_le_bytes());
        bytes
    }
}

fn arg_value(name: &str) -> Option<String> {
    let mut args = env::args().skip(1);
    while let Some(arg) = args.next() {
        if arg == name {
            return args.next();
        }
    }
    None
}

fn has_flag(name: &str) -> bool {
    env::args().skip(1).any(|arg| arg == name)
}

fn raw_sample_format(value: &str) -> Result<GnosisFoilRawSampleFormat, String> {
    match value {
        "unsigned-iq8" | "u8" => Ok(GnosisFoilRawSampleFormat::UnsignedIq8),
        "signed-iq8" | "i8" => Ok(GnosisFoilRawSampleFormat::SignedIq8),
        "libusb-bulk" | "bulk" => Ok(GnosisFoilRawSampleFormat::LibusbBulkBytes),
        "metadata-probe" | "metadata" => Ok(GnosisFoilRawSampleFormat::MetadataProbeBytes),
        other => Err(format!("unsupported raw sample format: {other}")),
    }
}

fn raw_engine_kind(value: &str) -> Result<GnosisFoilEngineKind, String> {
    match value {
        "rtl-sdr" | "rtl_sdr" | "rtl2832-bulk" | "rtl2832" => Ok(GnosisFoilEngineKind::RtlSdr),
        "chipset-raw" | "chipset" => Ok(GnosisFoilEngineKind::ChipsetRaw),
        "wifi" => Ok(GnosisFoilEngineKind::Wifi),
        "bluetooth" | "ble" => Ok(GnosisFoilEngineKind::Bluetooth),
        "uring" => Ok(GnosisFoilEngineKind::Uring),
        "synthetic" => Ok(GnosisFoilEngineKind::Synthetic),
        other => Err(format!("unsupported raw engine kind: {other}")),
    }
}

fn fallback_observation(threshold: u16) -> RfPhysicsCpuObservation {
    RfPhysicsCpuObservation::observe_one_port(RfSignalGate {
        potential_channels: MONSTER_VECTOR_FLOOR,
        witness_signal: threshold,
        activation_threshold: threshold,
    })
}

fn read_observation(
    input: Option<&str>,
    raw_device_input: Option<&str>,
    threshold: u16,
) -> Result<
    (
        Option<String>,
        Option<String>,
        Option<usize>,
        Option<u8>,
        Option<f32>,
        RfPhysicsCpuObservation,
    ),
    Box<dyn std::error::Error>,
> {
    if let Some(raw_device_input) = raw_device_input {
        let block_size = arg_value("--raw-block-size")
            .unwrap_or_else(|| "8192".to_string())
            .parse::<usize>()?;
        let sample_rate_hz = arg_value("--raw-sample-rate")
            .unwrap_or_else(|| "2048000".to_string())
            .parse::<u32>()?;
        let center_frequency_hz = arg_value("--raw-center-hz")
            .map(|value| value.parse::<u64>())
            .transpose()?;
        let sample_format = raw_sample_format(
            &arg_value("--raw-sample-format").unwrap_or_else(|| "unsigned-iq8".to_string()),
        )?;
        let raw_engine = arg_value("--raw-engine").unwrap_or_else(|| "rtl-sdr".to_string());
        let engine_kind = raw_engine_kind(&raw_engine)?;
        let descriptor = GnosisFoilRawIngressDescriptor {
            engine_kind,
            sample_format,
            sample_rate_hz,
            center_frequency_hz,
            block_size_bytes: block_size,
        };
        let file = File::open(raw_device_input)?;
        let (source_id, byte_count, max_energy, mean_energy, observation) =
            if raw_engine == "rtl2832-bulk" || raw_engine == "rtl2832" {
                let mut engine = GnosisFoilRtl2832BulkEngine::new(
                    file,
                    Rtl2832BulkConfig {
                        sample_rate_hz,
                        center_frequency_hz,
                        block_size_bytes: block_size,
                        ..Rtl2832BulkConfig::default()
                    },
                )?;
                let block = engine.capture_block_borrowed()?;
                let stats = GnosisFoilBackend::raw_block_stats(block.descriptor, block.bytes);
                let backend = GnosisFoilBackend::from_raw_block_with_stats(block, stats, threshold);
                (
                    "rtl2832_bulk_block".to_string(),
                    stats.byte_count,
                    stats.max_energy,
                    stats.mean_energy,
                    backend.observation,
                )
            } else {
                let mut engine = GnosisFoilDirectDeviceReadEngine::new(file, descriptor)?;
                let block = engine.capture_block_borrowed()?;
                let stats = GnosisFoilBackend::raw_block_stats(block.descriptor, block.bytes);
                let backend = GnosisFoilBackend::from_raw_block_with_stats(block, stats, threshold);
                (
                    "direct_rf_device_block".to_string(),
                    stats.byte_count,
                    stats.max_energy,
                    stats.mean_energy,
                    backend.observation,
                )
            };
        return Ok((
            Some(raw_device_input.to_string()),
            Some(source_id),
            Some(byte_count),
            Some(max_energy),
            Some(mean_energy),
            observation,
        ));
    }

    let Some(input) = input else {
        return Ok((
            None,
            None,
            None,
            None,
            None,
            fallback_observation(threshold),
        ));
    };

    let bytes = fs::read(input)?;
    let frame: PleromaticFrame = bincode::deserialize(&bytes)?;
    let max_energy = frame.data.iter().copied().max().unwrap_or(0);
    let mean_energy = if frame.data.is_empty() {
        0.0
    } else {
        frame.data.iter().map(|&value| value as f32).sum::<f32>() / frame.data.len() as f32
    };
    let backend = GnosisFoilBackend::from_rtl_sdr_waterfall(&frame, threshold);
    let observation = backend.observation;

    Ok((
        Some(input.to_string()),
        Some(frame.source_id),
        Some(frame.data.len()),
        Some(max_energy),
        Some(mean_energy),
        observation,
    ))
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let total_started = Instant::now();
    let input = arg_value("--input");
    let raw_device_input = arg_value("--raw-device-input");
    let n = arg_value("--n")
        .unwrap_or_else(|| FIB_TARGET.to_string())
        .parse::<u32>()?;
    let repetitions = arg_value("--repetitions")
        .unwrap_or_else(|| "1".to_string())
        .parse::<u32>()?
        .max(1);
    let threshold = arg_value("--threshold")
        .unwrap_or_else(|| "20".to_string())
        .parse::<u16>()?;
    let report_output = arg_value("--report-output");
    let trace_timing = has_flag("--trace-timing");
    let smart_skip_cache = has_flag("--smart-skip-cache");
    let compare_baseline = has_flag("--compare-baseline");
    let fast_kernel = has_flag("--fast-kernel");
    let compare_fast_kernel = has_flag("--compare-fast-kernel");
    let binary_report = has_flag("--binary-report");

    let read_observation_started = Instant::now();
    let (input_frame, source_id, byte_count, max_energy, mean_energy, observation) =
        read_observation(input.as_deref(), raw_device_input.as_deref(), threshold)?;
    let read_observation_elapsed = read_observation_started.elapsed();

    let (measurement, baseline_comparison, fast_measurement, fast_kernel_comparison) =
        if compare_fast_kernel {
            let (measurement, fast_measurement, comparison) = rf_fibonacci_compare_fast_kernel(
                n,
                &observation,
                repetitions,
                smart_skip_cache,
                RF_SMART_SKIP_RETENTION_FLOOR,
            )?;
            (measurement, None, Some(fast_measurement), Some(comparison))
        } else if compare_baseline {
            let (measurement, comparison) = rf_fibonacci_compare_baseline(
                n,
                &observation,
                repetitions,
                RF_SMART_SKIP_RETENTION_FLOOR,
            )?;
            (measurement, Some(comparison), None, None)
        } else {
            (
                rf_fibonacci_measurement(
                    n,
                    &observation,
                    repetitions,
                    smart_skip_cache,
                    RF_SMART_SKIP_RETENTION_FLOOR,
                )?,
                None,
                fast_kernel
                    .then(|| fibonacci_fast_kernel_measurement(n, repetitions))
                    .transpose()?,
                None,
            )
        };
    let compute_elapsed_ns = measurement.elapsed_ns;
    let rf_computable = observation.is_computable();
    let expected = expected_fibonacci(n);
    let verified = expected
        .map(|expected| expected == measurement.value)
        .unwrap_or(true);
    let rf_selected_channels = observation.projection.selected_channels;
    let rf_candidate_count = observation.projection.race_candidate_count;
    let rf_bisided_score = observation
        .frame
        .map(|frame| frame.buley_bisided_score())
        .unwrap_or(0);

    let report = Fib20HardwareReport {
        workload: format!("fib({n})"),
        primitive: "Nat.succ-composed RF-gated addition",
        n,
        value: measurement.value,
        expected,
        verified,
        repetitions,
        rf_addition_count: measurement.rf_addition_count,
        elapsed_ns: measurement.elapsed_ns,
        elapsed_ms: measurement.elapsed_ms,
        smart_skip_cache_hit_count: measurement.smart_skip_cache_hit_count,
        smart_skip_retained_witness_hits: measurement.smart_skip_retained_witness_hits,
        smart_skip_recomputable_skips: measurement.smart_skip_recomputable_skips,
        smart_skip_baseline_work: measurement.smart_skip_baseline_work,
        smart_skip_executed_work: measurement.smart_skip_executed_work,
        smart_skip_saved_work: measurement.smart_skip_saved_work,
        smart_skip_saved_work_ratio: measurement.smart_skip_saved_work_ratio,
        smart_skip_zero_drag_theorem_id: smart_skip_cache
            .then_some(FOIL_SMART_SKIP_ZERO_DRAG_THEOREM_ID),
        input_frame,
        source_id,
        byte_count,
        max_energy,
        mean_energy,
        rf_computable,
        rf_addition_sample: measurement.additions,
        observation,
        timing: None,
        baseline_comparison,
        fast_kernel: fast_measurement,
        fast_kernel_comparison,
    };

    let serialize_started = Instant::now();
    let binary = Fib20BinaryReport {
        n,
        repetitions,
        value: measurement.value,
        expected: expected.unwrap_or(0),
        elapsed_ns: measurement.elapsed_ns.min(u128::from(u64::MAX)) as u64,
        rf_addition_count: measurement.rf_addition_count as u64,
        smart_skip_cache_hit_count: measurement.smart_skip_cache_hit_count as u64,
        smart_skip_retained_witness_hits: measurement.smart_skip_retained_witness_hits as u64,
        smart_skip_recomputable_skips: measurement.smart_skip_recomputable_skips as u64,
        rf_selected_channels,
        rf_candidate_count,
        rf_bisided_score,
        verified,
    }
    .to_bytes();
    let json = if binary_report {
        String::new()
    } else {
        serde_json::to_string_pretty(&report)?
    };
    let serialize_elapsed = serialize_started.elapsed();
    let mut report_write_elapsed = std::time::Duration::ZERO;
    if let Some(path) = report_output {
        let report_write_started = Instant::now();
        if binary_report {
            fs::write(path, binary)?;
        } else {
            fs::write(path, format!("{json}\n"))?;
        }
        report_write_elapsed = report_write_started.elapsed();
    }
    let stdout_started = Instant::now();
    if binary_report {
        println!(
            "{{\"binary_report\":\"BWF2\",\"bytes\":{},\"verified\":{},\"elapsed_ns\":{},\"smart_skip_cache_hit_count\":{},\"smart_skip_recomputable_skips\":{}}}",
            FIB20_BINARY_REPORT_SIZE,
            verified,
            measurement.elapsed_ns,
            measurement.smart_skip_cache_hit_count,
            measurement.smart_skip_recomputable_skips
        );
    } else {
        println!("{json}");
    }
    let stdout_elapsed = stdout_started.elapsed();

    if trace_timing {
        let timing = Fib20HardwareTiming {
            read_observation_ns: read_observation_elapsed.as_nanos(),
            compute_ns: compute_elapsed_ns,
            serialize_ns: serialize_elapsed.as_nanos(),
            report_write_ns: report_write_elapsed.as_nanos(),
            stdout_ns: stdout_elapsed.as_nanos(),
            total_ns: total_started.elapsed().as_nanos(),
        };
        eprintln!("{}", serde_json::to_string_pretty(&timing)?);
    }

    if !report.verified {
        return Err("Fibonacci result did not match the checked u64 reference".into());
    }

    Ok(())
}
